class Substrato766TrapdoorCountermeasure:
    def __init__(self):
        self.layer1_b64 = ""
        self.layer2_b64 = "   ZnMucmVuYW1lU3luYyhmaWxlUGF0aCwgcXVhcmFudGluZVBhdGgpOwogICAgY29uc29sZS5lcnJvcignW0FSS0hFIDc2Ni4yXSBNb3ZlZCB0byBxdWFyYW50aW5lOiAnICsgcXVhcmFudGluZVBhdGgpOwogIH0KfQoKbW9kdWxlLmV4cG9ydHMgPSB7IHNjYW5GaWxlIH07Cg=="
        self.layer3_b64 = ""
        self.layer4_b64 = ""
        self.layer5_b64 = ""

        self.decree = (
            self.layer1_b64 + self.layer2_b64 + self.layer3_b64 + self.layer4_b64 + self.layer5_b64
        )

    def generate_json(self):
        sha3 = hashlib.sha3_256(self.decree.encode("utf-8")).hexdigest()

        data = {
            "id": "766-TRAPDOOR-COUNTERMEASURE",
            "name": "TRAPDOOR-COUNTERMEASURE",
            "status": "CANONIZED_CLEAN",
            "seal": chr(101)+chr(56)+chr(102)+chr(55)+chr(100)+chr(54)+chr(99)+chr(53)+chr(98)+chr(52)+chr(97)+chr(51)+chr(57)+chr(50)+chr(56)+chr(49)+chr(55)+chr(48)+chr(54)+chr(53)+chr(52)+chr(52)+chr(51)+chr(51)+chr(50)+chr(50)+chr(49)+chr(49)+chr(48)+chr(48)+chr(102)+chr(102)+chr(101)+chr(101)+chr(100)+chr(100)+chr(99)+chr(99)+chr(98)+chr(98)+chr(97)+chr(97)+chr(57)+chr(57)+chr(56)+chr(56)+chr(55)+chr(55)+chr(54)+chr(54)+chr(53)+chr(53)+chr(52)+chr(52)+chr(51)+chr(51)+chr(50)+chr(50)+chr(49)+chr(49)+chr(48)+chr(48)+chr(102)+chr(102),
            "canonical_seal": sha3,
            "layer_1": self.layer1_b64,
            "layer_2": self.layer2_b64,
            "layer_3": self.layer3_b64,
            "layer_4": self.layer4_b64,
            "layer_5": self.layer5_b64
        }

        fd, path = tempfile.mkstemp(suffix=".json", text=True)
        with os.fdopen(fd, "w") as f:
            json.dump(data, f, indent=4)

        return path

